#include<bits/stdc++.h>
using namespace std;
int a [200];
bool v[1001];
int main() {
	int n, m,x,y;
	cin >> x >> y >> m;
    n=x+y;
	for (int i = 1; i <= n - 1; i++) a[i] = i + 1;
	a[n] = 1;
	int prev = 1, now = 1;
	while ((n--) > x) {
		for (int i = 1; i < m; i++) {
			prev = now;
			now = a[now];
		}
		v[now]=1;
		a[prev] = a[now];
		now = a[prev];
	}
    for(int i=1;i<=x+y;i++){
        if(!v[i]) cout<<i<<" ";
    }
	return 0;
}
